'use client'

import React from 'react'
import Link from 'next/link'
import { usePathname } from 'next/navigation'
import {
    LayoutDashboard,
    Wallet,
    FileText,
    CheckCircle,
    Settings,
    BarChart3,
    LayoutGrid,
    LogOut,
} from 'lucide-react'
import { useBudget } from '@/context/BudgetContext'

export function Sidebar() {
    const { settings, logout, hasPermission } = useBudget()
    const pathname = usePathname()

    const navItems = [
        { id: '/dashboard', label: 'ภาพรวม', icon: LayoutDashboard },
        ...(hasPermission('view_budget') ? [{ id: '/budget', label: 'งบประมาณ', icon: Wallet }] : []),
        { id: '/request', label: 'ขอใช้งบประมาณ', icon: FileText },
        { id: '/report', label: 'รายงานผล', icon: CheckCircle },
        ...(hasPermission('manage_budget') || hasPermission('manage_departments') ? [{ id: '/management', label: 'การจัดการ', icon: Settings }] : []),
        ...(hasPermission('view_analytics') ? [{ id: '/analytics', label: 'วิเคราะห์', icon: BarChart3 }] : []),
        { id: '/settings', label: 'ตั้งค่า', icon: LayoutGrid },
    ]

    return (
        <aside className="hidden md:flex flex-col w-[260px] h-screen fixed top-0 left-0 z-20"
            style={{
                background: 'var(--surface-card)',
                borderRight: '1px solid var(--border-subtle)',
            }}>

            {/* ── Logo / Brand ── */}
            <div className="px-5 pt-6 pb-5">
                <div className="flex items-center gap-3">
                    <div className="w-9 h-9 rounded-xl flex items-center justify-center"
                        style={{ background: 'linear-gradient(135deg, #0066B3, #005191)' }}>
                        <Wallet className="w-[18px] h-[18px] text-white" strokeWidth={2} />
                    </div>
                    <div>
                        <p className="text-[13px] font-bold leading-tight" style={{ color: 'var(--text-primary)' }}>
                            {settings?.orgName || 'DCC Budget'}
                        </p>
                        <p className="text-[10px] font-medium tracking-wider uppercase"
                            style={{ color: 'var(--text-tertiary)' }}>
                            Budget Manager
                        </p>
                    </div>
                </div>
            </div>

            {/* Section label */}
            <div className="px-5 mb-2 mt-2">
                <p className="text-[11px] font-bold tracking-widest uppercase"
                    style={{ color: 'var(--text-tertiary)' }}>เมนูหลัก</p>
            </div>

            {/* ── Navigation ── */}
            <nav className="flex-1 px-4 space-y-1.5 overflow-y-auto no-scrollbar">
                {navItems.map((item) => {
                    const isActive = pathname === item.id || (item.id !== '/' && pathname?.startsWith(item.id))
                    return (
                        <Link
                            key={item.id}
                            href={item.id}
                            className={`flex items-center gap-3.5 px-4 py-3.5 rounded-[16px] text-[14px] font-semibold transition-all duration-200 group ${isActive
                                    ? 'bg-gradient-to-br from-[#0066B3] to-[#005191] text-white shadow-[0_4px_16px_rgba(0,102,179,0.25)]'
                                    : 'text-gray-500 hover:bg-primary-50 hover:text-primary-700'
                                }`}
                        >
                            <item.icon
                                className={`w-[20px] h-[20px] flex-shrink-0 transition-transform duration-200 group-hover:scale-110 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary-600'
                                    }`}
                                strokeWidth={isActive ? 2.5 : 2}
                            />
                            <span>{item.label}</span>
                        </Link>
                    )
                })}
            </nav>

            {/* ── Logout ── */}
            <div className="px-3 pb-4 pt-2" style={{ borderTop: '1px solid var(--border-subtle)' }}>
                <button
                    onClick={logout}
                    className="w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-[13px] font-medium transition-all duration-200 text-gray-500 hover:bg-red-50 hover:text-red-600"
                >
                    <LogOut className="w-[18px] h-[18px]" strokeWidth={1.8} />
                    <span>ออกจากระบบ</span>
                </button>
            </div>

            {/* ── Version ── */}
            <div className="px-5 pb-4">
                <p className="text-[10px]" style={{ color: 'var(--border-default)' }}>v2.0.0 • DCC Platform</p>
            </div>
        </aside>
    )
}
